<div class="page-head"><div><h1><?= e($module['name']) ?> Settings</h1><p class="muted">Operational settings for this module.</p></div><a class="btn light" href="<?= app_url('/'.$module['slug']) ?>">Back to Module</a></div><div class="grid two"><div class="card"><h3>Add / Update Setting</h3><form method="post" action="<?= app_url('/'.$module['slug'].'/settings/save') ?>"><input type="hidden" name="_csrf" value="<?= csrf_token() ?>"><label>Setting Key</label><input name="setting_key" placeholder="example.setting"><label>Setting Value</label><textarea name="setting_value" placeholder="value"></textarea><label>Type</label><select name="setting_type"><option>text</option><option>number</option><option>boolean</option><option>json</option></select><button class="btn primary">Save Setting</button></form></div><div class="card"><h3>Common Parameters</h3><p class="muted">Use this section for numbering, statuses, workflow, notifications, integration, approval rules, and operational parameters.</p></div></div><div class="card"><h3>Current Settings</h3><table data-searchable><thead><tr><th>Key</th><th>Value</th><th>Type</th><th>Updated</th></tr></thead><tbody><?php foreach($settings as $s): ?><tr><td><?= e($s['setting_key']) ?></td><td><?= e($s['setting_value']) ?></td><td><?= e($s['setting_type']) ?></td><td><?= e($s['updated_at']) ?></td></tr><?php endforeach; ?></tbody></table></div>
